use std::fmt;

trait Summarize {
    fn summary(&self) -> String;
}

struct Article { title: String, body: String }
struct Tweet { content: String }

impl Summarize for Article {
    fn summary(&self) -> String { self.title.clone() }
}
impl Summarize for Tweet {
    fn summary(&self) -> String { self.content.clone() }
}

// Returns a trait object
fn make_summary(is_article: bool) -> Box<dyn Summarize> {
    if is_article {
        Box::new(Article { title: String::from("news"), body: String::from("...") })
    } else {
        Box::new(Tweet { content: String::from("hello") })
    }
}

// Takes a trait object
fn print_all(items: &Vec<Box<dyn Summarize>>) {
    for item in items {
        println!("{}", item.summary());
    }
}
