use std::fmt;
use std::sync::{Arc, Mutex};

#[derive(Debug)]
pub enum StoreError {
    NotFound(String),
    Io(std::io::Error),
}

impl fmt::Display for StoreError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            StoreError::NotFound(k) => write!(f, "key not found: {k}"),
            StoreError::Io(e) => write!(f, "io error: {e}"),
        }
    }
}

impl std::error::Error for StoreError {}

impl From<std::io::Error> for StoreError {
    fn from(e: std::io::Error) -> Self { StoreError::Io(e) }
}

#[derive(Debug, Clone)]
pub struct Record {
    pub key: String,
    pub value: String,
}

pub struct Store {
    records: Arc<Mutex<Vec<Record>>>,
}

impl Store {
    pub fn new() -> Self {
        Store { records: Arc::new(Mutex::new(Vec::new())) }
    }

    pub fn insert(&self, key: &str, value: &str) {
        let mut records = self.records.lock().expect("mutex poisoned");
        records.push(Record { key: key.to_string(), value: value.to_string() });
    }

    pub fn find(&self, key: &str) -> Result<Record, StoreError> {
        let records = self.records.lock().expect("mutex poisoned");
        records
            .iter()
            .find(|r| r.key == key)
            .cloned()
            .ok_or_else(|| StoreError::NotFound(key.to_string()))
    }
}
